class Solution:
    def idealArrays(self, n, maxValue):
        MOD = 10**9 + 7
        # brute: count distinct ideal arrays directly via DP over (length, last value)
        # dp[v] = number of ideal arrays of current length ending in value v
        dp = [0] * (maxValue + 1)
        for v in range(1, maxValue + 1):
            dp[v] = 1
        for _ in range(n - 1):
            ndp = [0] * (maxValue + 1)
            for v in range(1, maxValue + 1):
                if dp[v] == 0:
                    continue
                m = v
                while m <= maxValue:
                    ndp[m] = (ndp[m] + dp[v]) % MOD
                    m += v
            dp = ndp
        return sum(dp) % MOD

