var idealArrays = function(n, maxValue) {
    const MOD = 1000000007n;
    let cur = new Array(maxValue + 1).fill(0n);
    for (let v = 1; v <= maxValue; v++) cur[v] = 1n;
    const chainCounts = [];
    const sumArr = (a) => { let s = 0n; for (const x of a) s = (s + x) % MOD; return s; };
    chainCounts.push(sumArr(cur));
    while (true) {
        const nxt = new Array(maxValue + 1).fill(0n);
        let any = false;
        for (let v = 1; v <= maxValue; v++) {
            if (cur[v] === 0n) continue;
            for (let m = 2 * v; m <= maxValue; m += v) {
                nxt[m] = (nxt[m] + cur[v]) % MOD;
                any = true;
            }
        }
        if (!any) break;
        chainCounts.push(sumArr(nxt));
        cur = nxt;
    }
    // precompute binomials comb(n-1, d-1) mod p via multiplicative formula
    const modpow = (b, e, m) => {
        let r = 1n; b %= m;
        while (e > 0n) { if (e & 1n) r = (r * b) % m; b = (b * b) % m; e >>= 1n; }
        return r;
    };
    const inv = (a) => modpow(a, MOD - 2n, MOD);
    let ans = 0n;
    // comb(n-1, k) incremental
    let combVal = 1n; // comb(n-1, 0)
    const N = BigInt(n - 1);
    for (let idx = 0; idx < chainCounts.length; idx++) {
        const kk = BigInt(idx); // d-1
        if (idx > 0) {
            // comb(n-1, idx) = comb(n-1, idx-1) * (n-idx) / idx; zero once idx > n-1
            if (kk > N) { combVal = 0n; }
            else {
                combVal = (combVal * ((N - kk + 1n) % MOD)) % MOD;
                combVal = (combVal * inv(kk % MOD)) % MOD;
            }
        }
        ans = (ans + (chainCounts[idx] * combVal) % MOD) % MOD;
    }
    return Number(ans % MOD);
};
